class BooleanExpressions {
  void examples() {
    bool isValid = true;
    bool condition = false;

    /// Double negation with double bang
    if (!!isValid) {
      print('valid');
    }

    /// Nested negation
    if (!(!condition)) {
      print('condition met');
    }

    /// Double negation in assignment
    final result = !!isValid;
    print(result);

    /// Double negation in variable declaration
    var flag = !!condition;

    /// Negation of negation in return
    if (!(!isValid)) {
      return;
    }

    /// Triple negation (still bad)
    bool x = !!!isValid;
  }
}

examples.good:
class BooleanExpressions {
  void examples() {
    bool isValid = true;
    bool condition = false;

    /// Direct boolean check
    if (isValid) {
      print('valid');
    }

    /// Single negation
    if (!condition) {
      print('condition met');
    }

    /// Direct assignment
    final result = isValid;
    print(result);

    /// Single negation in assignment
    var flag = !condition;

    /// Single negation in return
    if (isValid) {
      return;
    }

    /// Simple negation
    bool x = !isValid;
  }
}

examples.bad:
// Each conditional nested inside another conditional is flagged (the inner
// conditional, matching dart_code_linter's nesting-level reporting).

void doubleNesting() {
  final x = a ? (b ? c : d) : e;
  final y = condition ? (isValid ? "yes" : "no") : "default";
  final z = (first ? (second ? 1 : 2) : 3) + 4;
}

// Triple nesting flags both inner conditionals (nesting levels 2 and 3).
String getStatus() {
  return active ? (verified ? (premium ? "premium" : "standard") : "unverified") : "inactive";
}

class StatusHelper {
  String describe(bool a, bool b, bool c) {
    return a ? (b ? (c ? "all" : "a,b") : "a") : "none";
  }
}

int calculate(bool x, bool y) {
  return x ? (y ? (100) : (50)) : (0);
}

List<String> getItems(bool filter) {
  return filter ? (items.isNotEmpty ? (items.toList()) : []) : items;
}

