/// Cleanup before calling super.dispose
class GoodDisposeOrder extends ChangeNotifier {
  late AnimationController controller;
  late StreamSubscription subscription;

  @override
  void dispose() {
    controller.dispose();
    subscription.cancel();
    super.dispose();
  }
