// Public API surface exercising unused-code.

// Referenced from main.dart → live.
class PublicUsed {}

// Never referenced anywhere else → dead public class.
class PublicUnused {}

// Private: never a candidate, regardless of usage.
class _PrivateClass {}

// Annotated declarations are exempt (annotations often imply framework use).
@Deprecated('legacy')
class AnnotatedUnused {}

// Referenced from main.dart → live.
void usedFn() {}

// Never referenced elsewhere → dead public function.
void publicUnusedFn() {}

// Referenced within THIS file (by _useLocal) → used, not dead. dcl counts
// same-file references as usage, so this must NOT be flagged.
class OnlyLocal {}

// Never referenced anywhere, including its own file → dead public class.
class NeverReferenced {}

void _useLocal() {
  OnlyLocal();
  _PrivateClass();
}

// Referenced only from a string interpolation in THIS file → still used. The
// lexer folds interpolated identifiers into the string token, so the rule must
// look inside `${...}`; otherwise this is a false positive.
class InterpolatedOnly {}

String _describe() => 'value: ${InterpolatedOnly()}';

// Re-exports exported.dart; unused-code treats every public member of an
// exported file as used (the export surfaces the whole file's API).
export 'exported.dart';

// Exported by barrel.dart, so these public members are exempt from unused-code
// even though nothing references them directly.
class ExportedButUnused {}

void exportedApi() {}

import 'api.dart';

// Entrypoint that references the live public API from api.dart.
void main() {
  PublicUsed();
  usedFn();
}

// Referenced by main.dart, and owns a part file — both stay unflagged.
part 'feature_part.dart';

void runFeature() {
  featurePartHelper();
}

// A `part of` file: it belongs to feature.dart and is never a standalone unit,
// so unused-files must not flag it even though nothing imports it directly.
part of 'feature.dart';

void featurePartHelper() {
  print('part');
}

// Entrypoint: has main() and references the other live files, so nothing here
// is flagged and the files it imports count as used.
import 'used.dart';
import 'feature.dart';

void main() {
  helper();
  runFeature();
}

// Nothing imports/exports this file and it has no main(): it is dead code.
void orphanHelper() {
  print('orphan');
}

// Referenced by main.dart via `import 'used.dart'`, so it is NOT unused.
void helper() {
  print('helper');
}

